const item = $input.first().json || {};
const body = item.body || item;
const expectedPassword = 'gundam';
const password = String(body.password || '').trim();
const range = String(body.range || '30').trim();

return [{
  json: {
    ok: password && password === expectedPassword,
    range,
    response: {
      ok: false,
      message: '管理密碼錯誤或沒有權限'
    }
  }
}];

const auth = $('驗證管理密碼').first().json || {};
const range = auth.range || '30';
const batches = $('讀取掃描批次').all().map((item) => item.json || {});
const details = $input.all().map((item) => item.json || {});

function getValue(obj, keys) {
  for (const key of keys) {
    if (obj?.[key] !== undefined && obj?.[key] !== null) return obj[key];
  }
  return '';
}

function num(value) {
  const n = Number(String(value ?? '').replace(/,/g, '').trim());
  return Number.isFinite(n) ? n : 0;
}

function parseTime(value) {
  const raw = String(value || '').trim();
  if (!raw) return null;
  const time = new Date(raw);
  return Number.isNaN(time.getTime()) ? null : time;
}

function inRange(row) {
  if (range === 'all') return true;
  const days = Number(range || 30);
  if (!Number.isFinite(days)) return true;
  const time = parseTime(getValue(row, [
    '上傳時間', 'property_上傳時間', 'createdTime',
    'date:上傳時間:start', '日期', 'property_日期', 'date:日期:start'
  ]));
  if (!time) return true;
  const cutoff = new Date(Date.now() - days * 24 * 60 * 60 * 1000);
  return time >= cutoff;
}

function sameDay(date) {
  if (!date) return false;
  const now = new Date();
  return date.getFullYear() === now.getFullYear() && date.getMonth() === now.getMonth() && date.getDate() === now.getDate();
}

const scopedDetails = details.filter(inRange);
const scopedBatches = batches.filter(inRange);
const passedDetails = scopedDetails.filter((row) => getValue(row, ['比對結果', 'property_比對結果']) === 'OK');
const abnormalDetails = scopedDetails.filter((row) => getValue(row, ['比對結果', 'property_比對結果']) === '異常');

const operatorMap = new Map();
for (const row of scopedDetails) {
  const userId = String(getValue(row, ['LINE userId', 'property_LINE userId'])).trim();
  const name = String(getValue(row, ['操作人', 'property_操作人']) || userId || '未命名').trim();
  const key = userId || name;
  if (!operatorMap.has(key)) operatorMap.set(key, { name, userId, total: 0, passed: 0, abnormal: 0 });
  const item = operatorMap.get(key);
  item.total += 1;
  const status = getValue(row, ['比對結果', 'property_比對結果']);
  if (status === 'OK') item.passed += 1;
  if (status === '異常') item.abnormal += 1;
}

const operators = [...operatorMap.values()].map((operator) => ({
  ...operator,
  accuracy: operator.total ? operator.passed / operator.total : 0
})).sort((a, b) => b.total - a.total);

const recent = scopedBatches.map((batch) => {
  const total = num(getValue(batch, ['總筆數', 'property_總筆數']));
  const passed = num(getValue(batch, ['通過筆數', 'property_通過筆數']));
  const abnormal = num(getValue(batch, ['異常筆數', 'property_異常筆數']));
  return {
    time: getValue(batch, ['上傳時間', 'property_上傳時間', 'createdTime', 'date:上傳時間:start']),
    batchId: getValue(batch, ['批次ID', 'property_批次ID', '名稱', 'property_名稱']),
    operator: getValue(batch, ['操作人', 'property_操作人']),
    orderNo: getValue(batch, ['製令單號', 'property_製令單號']),
    total,
    passed,
    abnormal,
    accuracy: total ? passed / total : 0
  };
}).sort((a, b) => String(b.time).localeCompare(String(a.time))).slice(0, 20);

const totalItems = scopedDetails.length;
const passedItems = passedDetails.length;
const abnormalItems = abnormalDetails.length;
const todayBatches = scopedBatches.filter((batch) => sameDay(parseTime(getValue(batch, ['上傳時間', 'property_上傳時間', 'createdTime', 'date:上傳時間:start'])))).length;

return [{
  json: {
    ok: true,
    summary: {
      accuracy_rate: totalItems ? passedItems / totalItems : 0,
      total_items: totalItems,
      passed_items: passedItems,
      abnormal_items: abnormalItems,
      total_batches: scopedBatches.length,
      today_batches: todayBatches
    },
    operators,
    recent
  }
}];
